SELECT COUNT(proceeding_id) AS total_proceedings
FROM proceedings
WHERE date >= '2002-01-01' AND date <= '2002-12-31';

SELECT speaker_name
FROM speakers
WHERE speaker_id = 1;

SELECT speaker
FROM proceedings
WHERE speaker != (SELECT MIN(speaker) FROM proceedings);

SELECT COUNT(proceeding_id) AS discussion_count
FROM proceedings
WHERE topic = 'Broadband Infrastructure in the North West';

SELECT location, COUNT(proceeding_id) AS number_of_proceedings
FROM proceedings
GROUP BY location;

SELECT COUNT(*) 
FROM compliance 
WHERE compliance_status = 'non-compliant';

SELECT topic_name, description
FROM topics
WHERE category = 'economic' AND priority = 'high';
